const payload = $input.first().json.body ?? $input.first().json;
const intake = payload.intake ?? {};
const portalPath = payload.portalPath ?? payload.portal_path ?? null;
const publicBaseUrl = (payload.public_base_url ?? 'https://ai-employees-gamma.vercel.app').replace(/\/$/, '');
const portalUrl = portalPath?.startsWith('http') ? portalPath : portalPath ? `${publicBaseUrl}${portalPath}` : null;

const requiredFields = Array.isArray(intake.required_lead_fields)
  ? intake.required_lead_fields.join(', ')
  : intake.required_lead_fields ?? 'name, phone, email';

return [{
  json: {
    event: payload.event ?? 'ai_employee.customer_intake_submitted',
    source_app: payload.source_app ?? 'OBMC AI Employees',
    received_at: new Date().toISOString(),
    intake,
    portal_path: portalPath,
    portal_url: portalUrl,
    ghl_contact_payload: {
      locationId: payload.ghl_location_id ?? null,
      firstName: intake.contact_name ?? intake.business_name ?? 'AI Employee Customer',
      name: intake.contact_name ?? intake.business_name ?? 'AI Employee Customer',
      email: intake.email ?? null,
      phone: intake.phone ?? null,
      website: intake.website ?? null,
      tags: ['OBMC AI Employees', 'Intake Submitted', `Priority: ${intake.launch_priority ?? 'standard'}`],
      source: 'OBMC AI Employees customer intake',
      customFields: [
        { key: 'obmc_ai_industry', field_value: intake.industry ?? '' },
        { key: 'obmc_ai_service_area', field_value: intake.service_area ?? '' },
        { key: 'obmc_ai_services', field_value: intake.services_offered ?? '' },
        { key: 'obmc_ai_business_hours', field_value: intake.business_hours ?? '' },
        { key: 'obmc_ai_ideal_customer', field_value: intake.ideal_customer ?? '' },
        { key: 'obmc_ai_required_fields', field_value: requiredFields },
        { key: 'obmc_ai_launch_priority', field_value: intake.launch_priority ?? 'standard' }
      ]
    },
    ghl_note: [
      `AI Employee intake submitted for ${intake.business_name ?? intake.contact_name ?? 'customer'}.`,
      `Industry: ${intake.industry ?? 'not provided'}`,
      `Service area: ${intake.service_area ?? 'not provided'}`,
      `Services: ${intake.services_offered ?? 'not provided'}`,
      `FAQs: ${intake.common_questions ?? 'not provided'}`,
      `Appointment rules: ${intake.appointment_rules ?? 'not provided'}`,
      `Escalation contacts: ${intake.escalation_contacts ?? 'not provided'}`,
      `Tone: ${intake.tone_preferences ?? 'not provided'}`,
      `Disqualifying rules: ${intake.disqualifying_rules ?? 'not provided'}`,
      `GHL notes: ${intake.ghl_notes ?? 'not provided'}`,
      portalUrl ? `Portal: ${portalUrl}` : null
    ].filter(Boolean).join('\n'),
    implementation_tasks: [
      { owner: 'OBMC Admin', title: 'Review submitted intake', status: 'ready' },
      { owner: 'OBMC Admin', title: 'Draft AI Employee roles from intake', status: 'ready' },
      { owner: 'OBMC Admin', title: 'Map n8n and GHL handoffs', status: 'ready' },
      { owner: 'OBMC Admin', title: 'Prepare launch review checklist', status: 'ready' }
    ],
    next_step: 'update_ghl_contact_move_opportunity_to_implementation_and_notify_obmc'
  }
}];
